#include <iostream>

int main() {
    int n, m;
    std::cin >> n >> m;
    int a[100][100], b[100][100];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            std::cin >> a[i][j];
        }
    }
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            std::cin >> b[i][j];
        }
    }
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            std::cout << a[i][j] + b[i][j];
            if (j < m - 1) std::cout << " ";
        }
        std::cout << std::endl;
    }
    return 0;
}
